#include <iostream>
#include <vector>
#include <algorithm>
#include <cassert>
#include "618.cpp"

bool checkSorted(int arr[], int n, bool ascending) {
    for (int i = 0; i < n - 1; i++) {
        if (ascending) {
            if (arr[i] > arr[i + 1]) return false;
        } else {
            if (arr[i] < arr[i + 1]) return false;
        }
    }
    return true;
}

int main() {
    int arr1[] = {3, 1, 2};
    sortData(arr1, 3, 'a');
    assert(checkSorted(arr1, 3, true));

    int arr2[] = {1, 2, 3};
    sortData(arr2, 3, 'd');
    assert(checkSorted(arr2, 3, false));

    return 0;
}
